procedure.text:
create or replace function LoadProcessGroupTree() returns table( &&Id&& bigint, &&Name&& text, &&ParentId&& bigint ) as $$
with recursive t_Rec as ( select pg.&&Id&&, pg.&&Name&&, pg.&&Parent&& from &&ProcessGroup&& pg where pg.&&Parent&& is null union all select pgt.&&Id&&, pgt.&&Name&&, pgt.&&Parent&& from &&ProcessGroup&& pgt inner join t_Rec on t_Rec.&&Id&& = pgt.&&Parent&& ) select &&Id&&, &&Name&&, &&Parent&& as &&ParentId&& from t_Rec
$$ language sql;
